58	    type Handler = FifoChannelHandler<T>;
59	
60	    fn into_handler(self) -> (Callback<T>, Self::Handler) {
61	        let (sender, receiver) = flume::bounded(self.capacity);
62	        (
63	            Callback::from(move |t| {
64	                if let Err(error) = sender.send(t) {
65	                    tracing::error!(%error)
66	                }
67	            }),
68	            FifoChannelHandler(receiver),
69	        )
70	    }
71	}
