128	    /// Take all msgs currently sitting in the channel and produce an iterator over them. Unlike
129	    /// `try_iter`, the iterator will not attempt to fetch any more values from the channel once
130	    /// the function has been called.
131	    pub fn drain(&self) -> Drain<'_, T> {
132	        Drain(self.0.drain())
133	    }
134	
135	    /// Returns true if all senders for this channel have been dropped.
136	    pub fn is_disconnected(&self) -> bool {
137	        self.0.is_disconnected()
138	    }
139	
140	    /// Returns true if the channel is empty.
141	    /// Note: Zero-capacity channels are always empty.
142	    pub fn is_empty(&self) -> bool {
143	        self.0.is_empty()
144	    }
145	
146	    /// Returns true if the channel is full.
147	    /// Note: Zero-capacity channels are always full.
148	    pub fn is_full(&self) -> bool {
149	        self.0.is_full()
150	    }
151	
152	    /// Returns the number of messages in the channel.
153	    pub fn len(&self) -> usize {
154	        self.0.len()
155	    }
156	
157	    /// If the channel is bounded, returns its capacity.
158	    pub fn capacity(&self) -> Option<usize> {
159	        self.0.capacity()
160	    }
161	
162	    /// Get the number of senders that currently exist.
163	    pub fn sender_count(&self) -> usize {
164	        self.0.sender_count()
165	    }
166	
167	    /// Get the number of receivers that currently exist, including this one.
168	    pub fn receiver_count(&self) -> usize {
169	        self.0.receiver_count()
170	    }
171	
172	    /// Returns whether the receivers belong to the same channel.
173	    pub fn same_channel(&self, other: &Self) -> bool {
174	        self.0.same_channel(&other.0)
175	    }
176	}
