253	    /// Asynchronously receive a value from the channel, returning an error if all senders have been
254	    /// dropped. If the channel is empty, the returned future will yield to the async runtime.
255	    pub fn recv_async(&self) -> RecvFut<'_, T> {
256	        RecvFut(self.0.recv_async())
257	    }
258	
259	    /// Convert this receiver into a future that asynchronously receives a single message from the
260	    /// channel, returning an error if all senders have been dropped. If the channel is empty, this
261	    /// future will yield to the async runtime.
262	    pub fn into_recv_async<'a>(self) -> RecvFut<'a, T> {
263	        RecvFut(self.0.into_recv_async())
264	    }
265	}
