267	/// A future which allows asynchronously receiving a message.
268	///
269	/// Can be created via [`FifoChannelHandler::recv_async`] or [`FifoChannelHandler::into_recv_async`].
270	#[must_use = "futures/streams/sinks do nothing unless you `.await` or poll them"]
271	#[derive(Debug)]
272	pub struct RecvFut<'a, T>(flume::r#async::RecvFut<'a, T>);
273	
274	impl<T> Future for RecvFut<'_, T> {
275	    type Output = ZResult<T>;
276	
277	    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
278	        Future::poll(Pin::new(&mut self.0), cx).map_err(Into::into)
279	    }
280	}
281	
282	impl<T> futures::future::FusedFuture for RecvFut<'_, T> {
283	    fn is_terminated(&self) -> bool {
284	        futures::future::FusedFuture::is_terminated(&self.0)
285	    }
286	}
